import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import { ResponsiveChartContainer, LinePlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface RetentionData {
  day: number;
  retention: number;
}

interface EngagementMetrics {
  dauMauRatio: number;
  averageSessionDuration: number;
}

interface Data {
  engagementMetrics: EngagementMetrics;
  retentionCurve: RetentionData[];
}

export default function Widget() {
  const data = response.data as Data;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#121212', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FF5722', mb: 1 }}>
              User Engagement
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              DAU/MAU Ratio: {(data.engagementMetrics.dauMauRatio * 100).toFixed(1)}%
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5' }}>
              Avg. Session Duration: {data.engagementMetrics.averageSessionDuration.toFixed(1)} mins
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 200 }}>
            <ResponsiveChartContainer
              series={[
                {
                  type: 'line',
                  data: data.retentionCurve.map((d) => d.retention),
                  color: '#FF5722',
                  label: 'Retention',
                  curve: 'linear',
                },
              ]}
              xAxis={[
                {
                  scaleType: 'band',
                  data: data.retentionCurve.map((d) => `Day ${d.day}`),
                  id: 'days',
                },
              ]}
              yAxis={[{ id: 'retention', min: 0, max: 1 }]}
            >
              <g clipPath={`url(#${clipPathId})`}>
                <LinePlot />
              </g>
              <ChartsXAxis
                axisId="days"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsYAxis
                axisId="retention"
                tickLabelStyle={{ fontSize: 10, fill: '#B0BEC5' }}
              />
              <ChartsClipPath id={clipPathId} />
            </ResponsiveChartContainer>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
